args.sqlite_command:
DROP TABLE IF EXISTS J09B_temp;
CREATE TABLE J09B_temp AS
SELECT *
FROM decision_table
WHERE TOUR LIKE 'J09B%';
ALTER TABLE J09B_temp ADD COLUMN ENTSCHEIDUNG TEXT;

UPDATE J09B_temp
SET ENTSCHEIDUNG = (
  CASE
    WHEN (
      SELECT COUNT(DISTINCT t2.EQUNR)
      FROM J09B_temp t2
      WHERE t2.HAUS = J09B_temp.HAUS
    ) < 3 THEN 'KSA'
    ELSE 'EVU'
  END
);

UPDATE J09B_temp SET ENTSCHEIDUNG = 'EVU' WHERE HOUSE_NUM1 = 0;
UPDATE J09B_temp SET ENTSCHEIDUNG = 'EVU' WHERE HOUSE_NUM1 BETWEEN 500 AND 599;
UPDATE J09B_temp SET ENTSCHEIDUNG = 'EVU' WHERE HOUSE_NUM1 BETWEEN 900 AND 999;
UPDATE J09B_temp SET ENTSCHEIDUNG = 'EVU' WHERE CITY2 IN ('Wiblingwerde', 'Breckerfeld');

ALTER TABLE J09B_temp ADD COLUMN "Meter Reading (MR) Doc. No." TEXT;
ALTER TABLE J09B_temp ADD COLUMN TITLE TEXT;
ALTER TABLE J09B_temp ADD COLUMN FORENAME TEXT;
ALTER TABLE J09B_temp ADD COLUMN SURNAME TEXT;
ALTER TABLE J09B_temp ADD COLUMN STREET TEXT;
ALTER TABLE J09B_temp ADD COLUMN STREETNO TEXT;
ALTER TABLE J09B_temp ADD COLUMN final_CITY1 TEXT;
ALTER TABLE J09B_temp ADD COLUMN final_CITY2 TEXT;
ALTER TABLE J09B_temp ADD COLUMN final_POST_CODE1 INTEGER;
ALTER TABLE J09B_temp ADD COLUMN EMAIL TEXT;

UPDATE J09B_temp
SET "Meter Reading (MR) Doc. No." = (
  SELECT eg."Meter Reading (MR) Doc. No."
  FROM eablg eg
  WHERE eg.Installation = J09B_temp.ANLAGE
  LIMIT 1
);

UPDATE J09B_temp
SET
  TITLE = COALESCE((SELECT sm.TITLE FROM sales_master sm WHERE sm.EQUNR = J09B_temp.EQUNR LIMIT 1), (SELECT nm.TITLE FROM net_master nm WHERE nm.EQUNR = J09B_temp.EQUNR LIMIT 1)),
  FORENAME = COALESCE((SELECT sm.FORENAME FROM sales_master sm WHERE sm.EQUNR = J09B_temp.EQUNR LIMIT 1), (SELECT nm.FORENAME FROM net_master nm WHERE nm.EQUNR = J09B_temp.EQUNR LIMIT 1)),
  SURNAME = COALESCE((SELECT sm.SURNAME FROM sales_master sm WHERE sm.EQUNR = J09B_temp.EQUNR LIMIT 1), (SELECT nm.SURNAME FROM net_master nm WHERE nm.EQUNR = J09B_temp.EQUNR LIMIT 1)),
  STREET = COALESCE((SELECT sm.STREET FROM sales_master sm WHERE sm.EQUNR = J09B_temp.EQUNR LIMIT 1), (SELECT nm.STREET FROM net_master nm WHERE nm.EQUNR = J09B_temp.EQUNR LIMIT 1)),
  STREETNO = COALESCE((SELECT sm.STREETNO FROM sales_master sm WHERE sm.EQUNR = J09B_temp.EQUNR LIMIT 1), (SELECT nm.STREETNO FROM net_master nm WHERE nm.EQUNR = J09B_temp.EQUNR LIMIT 1)),
  final_CITY1 = COALESCE((SELECT sm.CITY1 FROM sales_master sm WHERE sm.EQUNR = J09B_temp.EQUNR LIMIT 1), (SELECT nm.CITY1 FROM net_master nm WHERE nm.EQUNR = J09B_temp.EQUNR LIMIT 1)),
  final_CITY2 = COALESCE((SELECT sm.CITY2 FROM sales_master sm WHERE sm.EQUNR = J09B_temp.EQUNR LIMIT 1), (SELECT nm.CITY2 FROM net_master nm WHERE nm.EQUNR = J09B_temp.EQUNR LIMIT 1)),
  final_POST_CODE1 = COALESCE((SELECT sm.POST_CODE1 FROM sales_master sm WHERE sm.EQUNR = J09B_temp.EQUNR LIMIT 1), (SELECT nm.POST_CODE1 FROM net_master nm WHERE nm.EQUNR = J09B_temp.EQUNR LIMIT 1)),
  EMAIL = COALESCE((SELECT sm.EMAIL FROM sales_master sm WHERE sm.EQUNR = J09B_temp.EQUNR LIMIT 1), (SELECT nm.EMAIL FROM net_master nm WHERE nm.EQUNR = J09B_temp.EQUNR LIMIT 1));

UPDATE J09B_temp
SET ENTSCHEIDUNG = 'MANDATORY_READING'
WHERE EQUNR IN (
  SELECT EQUNR
  FROM eabl
  WHERE ISTABLART_TXT = 'Maschinelle Schätzung - SAP'
    AND substr("Record created on",1,4) = '2024'
  INTERSECT
  SELECT EQUNR
  FROM eabl
  WHERE ISTABLART_TXT = 'Maschinelle Schätzung - SAP'
    AND substr("Record created on",1,4) = '2023'
);

UPDATE J09B_temp
SET ENTSCHEIDUNG = 'DIRECT_MAIL'
WHERE EQUNR IN (
  SELECT EQUNR
  FROM eabl
  WHERE ISTABLART_TXT = 'Ablesung durch Kunden - SAP'
    AND substr("Record created on",1,4) = '2024'
  INTERSECT
  SELECT EQUNR
  FROM eabl
  WHERE ISTABLART_TXT = 'Ablesung durch Kunden - SAP'
    AND substr("Record created on",1,4) = '2023'
);
